def transpose_spreadsheet(grid):
    if not grid or not grid[0]:
        return []
    rows = len(grid)
    cols = len(grid[0])
    result = []
    for c in range(cols):
        new_row = []
        for r in range(rows):
            new_row.append(grid[r][c])
        result.append(new_row)
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_2x3(self):
        self.assertEqual(transpose_spreadsheet([[1, 2, 3], [4, 5, 6]]), [[1, 4], [2, 5], [3, 6]])

    def test_spreadsheet_with_headers(self):
        grid = [["Name", "Age"], ["Alice", 30], ["Bob", 25]]
        expected = [["Name", "Alice", "Bob"], ["Age", 30, 25]]
        self.assertEqual(transpose_spreadsheet(grid), expected)

    def test_single_row(self):
        self.assertEqual(transpose_spreadsheet([[1, 2, 3]]), [[1], [2], [3]])

    def test_hidden_empty_grid(self):
        self.assertEqual(transpose_spreadsheet([]), [])

    def test_hidden_single_element(self):
        self.assertEqual(transpose_spreadsheet([["hello"]]), [["hello"]])

    def test_hidden_single_column(self):
        self.assertEqual(transpose_spreadsheet([[1], [2], [3]]), [[1, 2, 3]])

    def test_hidden_square_matrix(self):
        self.assertEqual(transpose_spreadsheet([[1, 2], [3, 4]]), [[1, 3], [2, 4]])

    def test_hidden_mixed_types(self):
        grid = [["Product", "Price", "Qty"], ["Apple", 1.5, 10], ["Banana", 0.75, 20]]
        expected = [["Product", "Apple", "Banana"], ["Price", 1.5, 0.75], ["Qty", 10, 20]]
        self.assertEqual(transpose_spreadsheet(grid), expected)

if __name__ == '__main__':
    unittest.main()
